#!/usr/bin/env node
/**
 * update-db-from-scrape.mjs — Обновляет Prisma из data/wb-scrape-result.json
 *
 * 1. Архивирует товары, которых нет на WB
 * 2. Добавляет новые товары с WB (генерация названия через name-generator.js)
 * 3. Обновляет цены, рейтинги, описания (с защитой descAutoGenerated)
 * 4. Обновляет характеристики, даты создания, фото
 *
 * Зависит от: wb-utils.mjs, wb-categories.js, name-generator.js
 *
 * Использование:
 *   node scripts/update-db-from-scrape.mjs
 */

import { readFileSync } from "fs";
import { PrismaClient } from "@prisma/client";
import { createRequire } from "module";
import {
  getVolPart,
  parseWbDate,
  cardCdnUrl,
  cardCdnUrls,
} from "./wb-utils.mjs";

const require = createRequire(import.meta.url);
const { wbToCategory } = require("./wb-categories.js");
const { generateName } = require("./name-generator.js");

const prisma = new PrismaClient();

/* =============================================
   Main
   ============================================= */

async function main() {
  console.log("=== update-db-from-scrape ===\n");

  const scrape = JSON.parse(readFileSync("data/wb-scrape-result.json", "utf-8"));
  const wbProducts = scrape.products;
  const wbArticles = new Set(wbProducts.map((p) => p.article));

  const dbProducts = await prisma.product.findMany({
    where: { wbArticle: { not: null } },
  });
  const dbByArticle = new Map();
  for (const p of dbProducts) {
    if (p.wbArticle) dbByArticle.set(p.wbArticle, p);
  }

  let archived = 0;
  let created = 0;
  let updated = 0;
  let skipped = 0;
  let namesGenerated = 0;
  let descriptionsUpdated = 0;
  let descriptionsSkipped = 0;

  // --- Шаг 1: Архивировать удалённые ---
  console.log("[1/5] Архивация товаров, которых нет на WB...");
  for (const p of dbProducts) {
    if (p.wbArticle && !wbArticles.has(p.wbArticle) && !p.archivedAt) {
      await prisma.product.update({
        where: { id: p.id },
        data: { archivedAt: new Date().toISOString() },
      });
      console.log("  Archived: " + p.id + " (article=" + p.wbArticle + ") " + p.name);
      archived++;
    }
  }
  console.log("  Done: " + archived + " archived\n");

  // --- Шаг 2: Добавить новые товары ---
  console.log("[2/5] Добавление новых товаров с WB...");
  for (const wb of wbProducts) {
    if (dbByArticle.has(wb.article)) continue;

    const maxId = await prisma.product.findFirst({ orderBy: { id: "desc" } });
    const nextNum = maxId ? parseInt(maxId.id.replace("mor-", "")) + 1 : 1;
    const newId = "mor-" + String(nextNum).padStart(3, "0");
    const slug = "wb-" + wb.article;

    // Категория через wb-categories.js
    const category = wbToCategory(wb.subjectId, wb.categoryName, wb.subjId);

    // Генерация названия
    const name = generateName({
      category,
      composition: wb.compositions || null,
      wbName: wb.name || wb.imtName || null,
    });

    // Дата создания на WB (ISO-строка "2024-08-15T14:05:36Z" или Unix timestamp)
    const wbCreated = parseWbDate(wb.wbCreatedAt);
    const wbUpdated = parseWbDate(wb.wbUpdatedAt);

    await prisma.product.create({
      data: {
        id: newId,
        slug,
        name,
        price: wb.priceProduct || 0,
        originalPrice: wb.priceBasic || 0,
        currency: "₽",
        category,
        description: wb.description || "",
        descAutoGenerated: true,
        image: cardCdnUrl(wb.article, 1),
        images: cardCdnUrls(wb.article, wb.photoCount || wb.pics || 1),
        wbArticle: wb.article,
        imtId: wb.imtId || null,
        colorName: wb.colorName || null,
        composition: wb.compositions || null,
        rating: wb.rating || null,
        reviewsCount: wb.feedbacks || null,
        nameAutoGenerated: true,
        characteristics: wb.cardOptions || [],
        wbCreatedAt: wbCreated,
        wbUpdatedAt: wbUpdated,
      },
    });

    console.log("  Created: " + newId + " (article=" + wb.article + ") " + name);
    created++;
  }
  console.log("  Done: " + created + " created\n");

  // --- Шаг 3: Обновить цены, рейтинги, фото ---
  console.log("[3/5] Обновление цен, рейтингов, фото...");
  for (const wb of wbProducts) {
    const db = dbByArticle.get(wb.article);
    if (!db) continue;

    const updateData = {};
    let changed = false;

    // Цены
    if (wb.priceProduct !== null && wb.priceProduct !== db.price) {
      updateData.price = wb.priceProduct;
      changed = true;
    }
    if (wb.priceBasic !== null && wb.priceBasic !== db.originalPrice) {
      updateData.originalPrice = wb.priceBasic;
      changed = true;
    }

    // Рейтинг
    if (wb.rating !== null && wb.rating !== db.rating) {
      updateData.rating = wb.rating;
      changed = true;
    }

    // Отзывы
    if (wb.feedbacks !== null && wb.feedbacks !== db.reviewsCount) {
      updateData.reviewsCount = wb.feedbacks;
      changed = true;
    }

    // Фото (если их стало больше)
    const photoCount = wb.photoCount || wb.pics || 0;
    if (photoCount > 0) {
      const currentCount = db.images ? db.images.length : 0;
      if (photoCount > currentCount) {
        const newImages = cardCdnUrls(wb.article, photoCount);
        updateData.images = newImages;
        if (newImages.length > 0) updateData.image = newImages[0];
        changed = true;
      }
    }

    if (changed) {
      await prisma.product.update({
        where: { id: db.id },
        data: updateData,
      });
      updated++;
    }
  }
  console.log("  Updated prices/ratings: " + updated + "\n");

  // --- Шаг 4: Обновить характеристики, названия, описания ---
  console.log("[4/5] Обновление характеристик, названий, описаний...");
  let step4changes = 0;

  for (const wb of wbProducts) {
    const db = dbByArticle.get(wb.article);
    if (!db) continue;

    const updateData = {};
    let changed = false;

    // --- Название (всегда генерируем для WB товаров) ---
    const category = wbToCategory(wb.subjectId, wb.categoryName, wb.subjId);
    const newName = generateName({
      category,
      composition: wb.compositions || db.composition || null,
      wbName: wb.name || wb.imtName || null,
    });
    if (newName !== db.name) {
      updateData.name = newName;
      updateData.nameAutoGenerated = true;
      changed = true;
      namesGenerated++;
    }

    // --- Описание (только если было авто-сгенерировано) ---
    if (wb.description && wb.description !== db.description) {
      if (db.descAutoGenerated !== false) {
        // descAutoGenerated === true || null → обновляем
        updateData.description = wb.description;
        updateData.descAutoGenerated = true;
        changed = true;
        descriptionsUpdated++;
      } else {
        descriptionsSkipped++;
      }
    }

    // --- Категория (по wb-categories) ---
    if (category !== db.category) {
      updateData.category = category;
      changed = true;
    }

    // --- Цвет и состав ---
    if (wb.colorName && wb.colorName !== db.colorName) {
      updateData.colorName = wb.colorName;
      changed = true;
    }
    if (wb.compositions && wb.compositions !== db.composition) {
      updateData.composition = wb.compositions;
      changed = true;
    }

    // --- Характеристики (cardOptions — иерархические) ---
    if (wb.cardOptions && Array.isArray(wb.cardOptions) && wb.cardOptions.length > 0) {
      const current = db.characteristics;
      const newVal = JSON.stringify(wb.cardOptions);
      if (!current || JSON.stringify(current) !== newVal) {
        updateData.characteristics = wb.cardOptions;
        changed = true;
      }
    }

    // --- Даты создания/обновления на WB ---
    if (wb.wbCreatedAt && !db.wbCreatedAt) {
      updateData.wbCreatedAt = parseWbDate(wb.wbCreatedAt);
      changed = true;
    }
    if (wb.wbUpdatedAt) {
      const newUpdated = parseWbDate(wb.wbUpdatedAt);
      if (!db.wbUpdatedAt || +newUpdated !== +db.wbUpdatedAt) {
        updateData.wbUpdatedAt = newUpdated;
        changed = true;
      }
    }

    // --- IMT ID (если не было) ---
    if (wb.imtId && !db.imtId) {
      updateData.imtId = wb.imtId;
      changed = true;
    }

    if (changed) {
      await prisma.product.update({
        where: { id: db.id },
        data: updateData,
      });
      step4changes++;
    }
  }
  console.log("  Names generated: " + namesGenerated);
  console.log("  Descriptions updated: " + descriptionsUpdated);
  console.log("  Descriptions skipped (manual): " + descriptionsSkipped);
  console.log("  Products with changes: " + step4changes + "\n");

  // --- Шаг 5: Итоги ---
  console.log("[5/5] Итоги:");
  const total = await prisma.product.count();
  const active = await prisma.product.count({ where: { archivedAt: null } });
  const withWb = await prisma.product.count({ where: { wbArticle: { not: null } } });
  const withChars = await prisma.product.count({ where: { characteristics: { not: null } } });
  const withDates = await prisma.product.count({ where: { wbCreatedAt: { not: null } } });
  console.log("  Всего товаров: " + total);
  console.log("  Активных: " + active);
  console.log("  С WB артикулом: " + withWb);
  console.log("  С характеристиками: " + withChars);
  console.log("  С датой создания на WB: " + withDates);
  console.log("  Архивировано: " + archived);
  console.log("  Добавлено: " + created);
  console.log("  Обновлено (цены/рейтинги): " + updated);
  console.log("  Изменено (характеристики/названия): " + step4changes);
  console.log("  Сгенерировано названий: " + namesGenerated);
}

main()
  .catch((e) => {
    console.error("FATAL:", e);
    process.exit(1);
  })
  .finally(() => prisma.$disconnect());
